import json
import statistics

# Get massage therapy businesses
thekey = 'var_functions.query_db:8'
mb = locals()[thekey]

# Get reviews data
thekey2 = 'var_functions.query_db:18'
rd = locals()[thekey2]

# Create mapping of gmap_id to business names
gmap_to_name = {}
for b in mb:
    name_lower = b.get('name', '').lower()
    desc_lower = b.get('description', '').lower()
    if 'massage' in name_lower or 'massage therapy' in desc_lower or 'bodywork' in desc_lower or 'spa' in name_lower:
        if not any(k in name_lower for k in ['oracle', 'gallery', 'ibew', 'entrance', 'highpoint']):
            gmap_to_name[b['gmap_id']] = b['name']

# Calculate average ratings for each massage business
ratings_by_business = {}
for gid in gmap_to_name:
    ratings_by_business[gid] = []

# Collect all ratings
for r in rd:
    gid = r['gmap_id']
    if gid in ratings_by_business:
        ratings_by_business[gid].append(int(r['rating']))

# Calculate averages and filter for >= 4.0
results = []
for gid, ratings in ratings_by_business.items():
    if ratings:
        avg_rating = statistics.mean(ratings)
        if avg_rating >= 4.0:
            results.append({
                'business_name': gmap_to_name[gid],
                'gmap_id': gid,
                'average_rating': round(avg_rating, 2),
                'review_count': len(ratings)
            })

# Sort by average rating desc
results.sort(key=lambda x: x['average_rating'], reverse=True)

# Output
output = []
for r in results:
    output.append('{}: {}'.format(r['business_name'], r['average_rating']))

print('__RESULT__:')
print(json.dumps(output))

